//#region src/mpesa/reversal/types.d.ts
/**
 * Transaction Reversal types
 *
 * API: POST /mpesa/reversal/v1/request
 *
 * Reverses a completed M-PESA transaction. The result is asynchronous —
 * POSTed to your ResultURL after processing.
 *
 * Required org portal role: "Reversal ORG API initiator"
 *
 * Reversal identifiers:
 *   "1" = MSISDN (customer phone)
 *   "2" = Till Number
 *   "4" = Organisation ShortCode (Paybill / B2C)
 *   "11" = Reversal (used internally by Daraja — not for request)
 *
 * Ref: Transaction Reversal — Daraja Developer Portal
 */
interface ReversalRequest {
  /**
   * The M-PESA transaction ID to reverse (e.g. "OEI2AK4XXXX").
   * Daraja field: TransactionID
   */
  transactionId: string;
  /**
   * Your business shortcode requesting the reversal.
   * Daraja field: ReceiverParty
   */
  receiverParty: string;
  /**
   * Identifier type for ReceiverParty.
   *   "1" = MSISDN
   *   "2" = Till Number
   *   "4" = Organisation ShortCode
   * Daraja field: RecieverIdentifierType
   */
  receiverIdentifierType: '1' | '2' | '4';
  /**
   * URL where Safaricom POSTs the reversal result.
   * Daraja field: ResultURL
   */
  resultUrl: string;
  /**
   * URL called when the request times out in the queue.
   * Daraja field: QueueTimeOutURL
   */
  queueTimeOutUrl: string;
  /**
   * Amount to reverse. Must equal the original transaction amount.
   * Daraja field: Amount
   */
  amount: number;
  /** Short remarks (up to 100 characters) */
  remarks?: string;
  /** Additional occasion string */
  occasion?: string;
}
interface ReversalResponse {
  OriginatorConversationID: string;
  ConversationID: string;
  /** "0" = request accepted */
  ResponseCode: string;
  ResponseDescription: string;
}
//#endregion
//#region src/mpesa/tax-remittance/types.d.ts
/**
 * Tax Remittance types
 *
 * API: POST /mpesa/b2b/v1/remittax
 *
 * NOTE: This is an ASYNCHRONOUS API.
 * The synchronous response only confirms Safaricom received the request.
 * The actual result arrives later via POST to your ResultURL.
 *
 * Ref: Tax Remittance — Daraja Developer Portal
 */
interface TaxRemittanceRequest {
  /**
   * The transaction amount to remit to KRA.
   * Must be a whole number ≥ 1.
   * Daraja field: Amount
   */
  amount: number;
  /**
   * Your own M-PESA business shortcode from which the money is deducted.
   * Daraja field: PartyA
   */
  partyA: string;
  /**
   * The KRA account to which money is credited.
   * For Tax Remittance, only "572572" is allowed.
   * Defaults to "572572" if omitted.
   * Daraja field: PartyB
   */
  partyB?: string;
  /**
   * The Payment Registration Number (PRN) issued by KRA.
   * This is your tax declaration reference from KRA.
   * Daraja field: AccountReference
   */
  accountReference: string;
  /**
   * URL where Safaricom POSTs the final result after processing.
   * Must be publicly accessible.
   * Daraja field: ResultURL
   */
  resultUrl: string;
  /**
   * URL Safaricom calls when the request times out in the queue.
   * Must be publicly accessible.
   * Daraja field: QueueTimeOutURL
   */
  queueTimeOutUrl: string;
  /**
   * Optional remarks (up to 100 characters).
   * Daraja field: Remarks
   */
  remarks?: string;
}
interface TaxRemittanceResponse {
  /** Unique request identifier assigned by Daraja upon successful submission */
  OriginatorConversationID: string;
  /** Unique request identifier assigned by M-Pesa upon successful submission */
  ConversationID: string;
  /** "0" = successful submission */
  ResponseCode: string;
  /** Human-readable status description */
  ResponseDescription: string;
}
/**
 * Known result parameter keys for Tax Remittance.
 *
 * `(string & {})` is used as the catch-all so that:
 *   - Named literals appear in IntelliSense / autocomplete.
 *   - Any unknown future key Daraja may return is still accepted.
 *   - The `no-redundant-type-constituents` ESLint rule is not triggered.
 */
type TaxRemittanceResultParameterKey = 'DebitAccountBalance' | 'Amount' | 'DebitPartyAffectedAccountBalance' | 'TransCompletedTime' | 'DebitPartyCharges' | 'ReceiverPartyPublicName' | 'Currency' | 'InitiatorAccountCurrentBalance' | (string & {});
interface TaxRemittanceResultParameter {
  Key: TaxRemittanceResultParameterKey;
  Value: string | number;
}
interface TaxRemittanceResult {
  Result: {
    /** Usually "0" */ResultType: string; /** 0 = success */
    ResultCode: number; /** Human-readable result description */
    ResultDesc: string;
    OriginatorConversationID: string;
    ConversationID: string;
    TransactionID: string;
    ResultParameters?: {
      ResultParameter: TaxRemittanceResultParameter[];
    };
    ReferenceData?: {
      ReferenceItem: {
        Key: string;
        Value: string;
      } | Array<{
        Key: string;
        Value: string;
      }>;
    };
  };
}
